# This script downloads all CSV files from a specified S3 bucket and prefix,
# concatenates them into a single DataFrame, and saves the result as a CSV file.
# It requires the boto3 and pandas libraries to be installed.
# THIS IS GENERATED BY GITHUB COPILOT

import boto3
import pandas as pd
import io

bucket = "local-gov-ai-llm-benchmarking"
prefix = "output/"
s3 = boto3.client("s3")

# List all CSV files under the output/ folder (including subfolders)
csv_keys = []
response = s3.list_objects_v2(Bucket=bucket, Prefix=prefix)
while True:
    for obj in response.get("Contents", []):
        key = obj["Key"]
        if key.endswith(".csv"):
            csv_keys.append(key)
    # Handle pagination
    if response.get("IsTruncated"):
        response = s3.list_objects_v2(Bucket=bucket, Prefix=prefix, ContinuationToken=response["NextContinuationToken"])
    else:
        break

# Download and concatenate all CSVs
dfs = []
for key in csv_keys:
    obj = s3.get_object(Bucket=bucket, Key=key)
    df = pd.read_csv(io.BytesIO(obj["Body"].read()))
    dfs.append(df)

# Concatenate rowwise
combined_df = pd.concat(dfs, ignore_index=True)
# Remove columns that begin with "Unnamed"
combined_df = combined_df.loc[:, ~combined_df.columns.str.startswith("Unnamed")]

# Export back to S3
combined_csv_buffer = io.StringIO()
combined_df.to_csv(combined_csv_buffer, index=False)
s3.put_object(
    Bucket=bucket,
    Key="output/all_output_combined.csv",
    Body=combined_csv_buffer.getvalue()
)